import { useEffect } from 'react';

/**
 * A custom hook which scrolls the focused element into view inside a given
 * container.
 *
 * @param {Object} options
 * @param {React.RefObject} options.root - the ref of the root element
 * @param {string} options.behavior - the scroll behavior
 * @param {string} options.block - the scroll block
 * @param {string} options.inline - the scroll inline
 * @todo there is sometimes a jump in the page when the buttons are clicked. Not
 * sure if this is the cause.
 */
const useScrollToFocusedElement = ({
  root,
  behavior = 'smooth',
  block = 'nearest',
  inline = 'center',
}) =>
  useEffect(() => {
    const container = root.current;
    const handleFocused = () => {
      const focusWithin = root?.contains(document.activeElement);
      if (focusWithin) {
        document.activeElement.scrollIntoView({
          behavior,
          block,
          inline,
        });
      }
    };

    container?.addEventListener('focusin', handleFocused);
    container?.addEventListener('focusout', handleFocused);

    return () => {
      container?.removeEventListener('focusin', handleFocused);
      container?.removeEventListener('focusout', handleFocused);
    };
  }, [root, behavior, block, inline]);

export default useScrollToFocusedElement;
