import { useCallback, useRef, useEffect } from 'react';

import chunk from '#utils/chunk';
import clamp from '#utils/clamp';

import { INITIAL_INDEX, INCREMENT } from './Carousel.constants';
import { Boundary, Slider, Nav, Group } from './Carousel.styles';
import propTypes from './Carousel.types';
import useScrollToFocusedElement from './hooks/useScrollToFocusedElement';
import useVisibleIndexes from './hooks/useVisibleIndexes';

const Carousel = ({
  className,
  items,
  ButtonNext,
  ButtonPrev,
  renderSlide,
  ...props
}) => {
  const { initialIndex = INITIAL_INDEX, increment = INCREMENT } = props;
  const itemsArray = items;
  const groupsOfItems = chunk(itemsArray, increment);
  const sliderRef = useRef();
  const groupRefs = useRef([]);
  const childrenRefs = useRef([]);
  const min = 0;
  const max = items.length - 1;
  const [visibleIndexes, isAtStart, isAtEnd] = useVisibleIndexes({
    nodes: groupRefs.current,
    root: sliderRef,
  });
  const showNav = !(isAtStart && isAtEnd);

  const navigate = useCallback(
    (newIndex = 0) => {
      const index = clamp(min, max, newIndex);
      const top = 0;
      const left = groupRefs?.current?.at(index)?.offsetLeft;
      const behavior = 'smooth';

      /*
       * `scrollIntoView()` is not consistent across browsers.
       * Chrome doesn't scroll to the left edge of the item when the
       * slider is already aligned to the viewport.
       */
      sliderRef?.current?.scrollTo({
        top,
        left,
        behavior,
      });
    },
    [sliderRef, min, max],
  );

  useEffect(() => {
    navigate(initialIndex);
  }, [initialIndex, navigate]);

  useScrollToFocusedElement({
    root: sliderRef,
    behavior: 'smooth',
    block: 'nearest',
    inline: 'center',
  });

  const navigateCarousel = useCallback(
    (adjust) => {
      const index = visibleIndexes.findIndex((x) => x);
      const newIndex = clamp(min, max, index + adjust);
      navigate(newIndex);
    },
    [visibleIndexes, max, navigate],
  );

  const handlePrevClick = () => navigateCarousel(-1);
  const handleNextClick = () => navigateCarousel(1);

  return (
    <Boundary className={className}>
      <Slider ref={sliderRef}>
        {groupsOfItems.map((group, groupIndex) => (
          <Group
            key={groupIndex}
            ref={(ref) => (groupRefs.current[groupIndex] = ref)}
          >
            {group.map((item, i) =>
              renderSlide({
                slideIndex: i,
                itemIndex: groupIndex * increment + i,
                item,
                isVisible: !!visibleIndexes[groupIndex],
                ref: (ref) => {
                  childrenRefs.current[i] = ref;
                },
              }),
            )}
          </Group>
        ))}
      </Slider>
      {showNav && (
        <Nav>
          <ButtonPrev disabled={isAtStart} onClick={handlePrevClick} />
          <ButtonNext disabled={isAtEnd} onClick={handleNextClick} />
        </Nav>
      )}
    </Boundary>
  );
};
Carousel.displayName = 'Carousel';
Carousel.propTypes = propTypes;

export default Carousel;
