import { useEffect, useRef, useState } from 'react';

/**
 * useVisibleIndexes
 * This is a custom hook that uses the IntersectionObserver API to determine
 * whether refs are visible or not.
 *
 * @param {Object} options
 * @param {Array<React.RefObject>} options.nodes - an array of refs to observe
 * @param {React.RefObject} options.root - the ref of the root element
 *
 * @returns {Array<boolean>} visibleIndexes - an array of booleans that indicate whether the items are visible or not
 */
const useVisibleIndexes = ({ nodes, root }) => {
  const observer = useRef(null);
  const [visibleIndexes, setVisibleIndexes] = useState(nodes.map(() => false));
  const [isAtStart, setIsAtStart] = useState(true);
  const [isAtEnd, setIsAtEnd] = useState(true);

  useEffect(() => {
    const handleIntersect = (entries) =>
      entries.forEach((entry) => {
        const { target, isIntersecting, intersectionRatio } = entry;
        const entryIndex = nodes.findIndex((node) => node === target);
        const isCompletelyVisible = isIntersecting && intersectionRatio > 0.9;
        const isPartlyVisible = isIntersecting && intersectionRatio > 0.1;
        const isFirst = entryIndex === 0;
        const isLast = entryIndex === nodes.length - 1;

        setVisibleIndexes((prev) => {
          const next = [...prev];
          next[entryIndex] = isPartlyVisible;
          return next;
        });

        isFirst && setIsAtStart(isCompletelyVisible);
        isLast && setIsAtEnd(isCompletelyVisible);
      });

    observer.current = new IntersectionObserver(handleIntersect, {
      threshold: [0.1, 0.5, 0.9],
      root: root.current,
      rootMargin: '-1px',
    });

    nodes.forEach((ref) => {
      observer.current?.observe(ref);
    });

    return () => observer.current?.disconnect();
  }, [root, nodes]);

  return [visibleIndexes, isAtStart, isAtEnd];
};

export default useVisibleIndexes;
